export default function UserLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return <div className="-mt-6">{children}</div>
}

"use client"
import {
  NavigationItem,
} from "@/components/atoms"
import { useUnreads } from "@talkjs/react"
import { usePathname } from "next/navigation"

const navigationItems = [
  { label: "Orders", href: "/user/orders" },
  { label: "Messages", href: "/user/messages" },
  { label: "Returns", href: "/user/returns" },
  { label: "Addresses", href: "/user/addresses" },
  { label: "Reviews", href: "/user/reviews" },
  { label: "Wishlist", href: "/user/wishlist" },
]

export const UserNavigation = () => {
  const unreads = useUnreads()
  const path = usePathname()

  return (
    <nav
      className="h-min rounded-[14px] overflow-hidden"
      style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
    >
      <div className="py-2">
        {navigationItems.map((item) => (
          <NavigationItem
            key={item.label}
            href={item.href}
            active={path === item.href}
            className="relative"
          >
            {item.label}
            {item.label === "Messages" && Boolean(unreads?.length) && (
              <span
                className="absolute top-3 left-24 w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold text-white"
                style={{ background: "var(--brand-primary, #8B5CF6)" }}
              >
                {unreads?.length}
              </span>
            )}
          </NavigationItem>
        ))}
      </div>
      <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)" }} className="py-2">
        <NavigationItem
          href="/user/settings"
          active={path === "/user/settings"}
        >
          Settings
        </NavigationItem>
      </div>
    </nav>
  )
}

"use client"

import { useState, useEffect } from "react"
import { HttpTypes } from '@medusajs/types'
import { formatAmount } from "@/lib/helpers/money"
import { cn } from "@/lib/utils"
import { CreatePriceAlertModal } from "./CreatePriceAlertModal"
import { toast } from "sonner"

interface PriceAlert {
  id: string
  user_id: string
  catalog_sku: string
  card_name: string
  card_image?: string
  set_name?: string
  alert_type: 'PRICE_DROP' | 'PRICE_TARGET' | 'BACK_IN_STOCK' | 'NEW_LISTING'
  trigger_price?: number
  percentage_threshold?: number
  condition_filter?: string
  language_filter?: string
  email_enabled: boolean
  sms_enabled: boolean
  push_enabled: boolean
  status: 'ACTIVE' | 'TRIGGERED' | 'EXPIRED' | 'PAUSED'
  baseline_price?: number
  current_price?: number
  last_triggered_at?: string
  trigger_count: number
  max_triggers: number
  expires_at?: string
  created_at: string
  updated_at: string
}

interface CreateAlertRequest {
  catalog_sku: string
  alert_type: string
  trigger_price?: number
  percentage_threshold?: number
  condition_filter?: string
  language_filter?: string
  email_enabled: boolean
  sms_enabled: boolean
  push_enabled: boolean
  expires_at?: string
  max_triggers?: number
}

interface EnhancedPriceAlertsProps {
  customer: HttpTypes.StoreCustomer
  catalogSku?: string // Optional - if provided, shows alerts for specific card
  card?: {
    id: string
    name: string
    set_name?: string
    image_url?: string
  }
  currentPrice?: number
  className?: string
}

export function EnhancedPriceAlerts({ customer, catalogSku, card, currentPrice, className }: EnhancedPriceAlertsProps) {
  const [alerts, setAlerts] = useState<PriceAlert[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [filter, setFilter] = useState<'all' | 'active' | 'triggered' | 'paused'>('all')
  const [sortBy, setSortBy] = useState<'created_at' | 'trigger_price' | 'card_name'>('created_at')

  useEffect(() => {
    loadAlerts()
  }, [customer.id, catalogSku, filter])

  const loadAlerts = async () => {
    try {
      setLoading(true)
      setError(null)
      
      const params = new URLSearchParams()
      if (catalogSku) params.append('catalog_sku', catalogSku)
      if (filter !== 'all') params.append('status', filter.toUpperCase())
      params.append('sort_by', sortBy)
      
      const response = await fetch(`${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/users/${customer.id}/price-alerts?${params}`)
      
      if (response.ok) {
        const { data } = await response.json()
        setAlerts(data.alerts || [])
      } else {
        throw new Error('Failed to load price alerts')
      }
    } catch (error) {
      console.error('Error loading alerts:', error)
      setError('Failed to load price alerts')
    } finally {
      setLoading(false)
    }
  }

  const handleDeleteAlert = async (alertId: string) => {
    try {
      const response = await fetch(`${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/users/${customer.id}/price-alerts/${alertId}`, {
        method: 'DELETE'
      })
      
      if (response.ok) {
        setAlerts(alerts.filter(alert => alert.id !== alertId))
      } else {
        const error = await response.json()
        toast.error(error.message || 'Something went wrong removing that alert. Try again in a moment.')
      }
    } catch (error) {
      console.error('Error deleting alert:', error)
      toast.error('Something went wrong removing that alert. Try again in a moment.')
    }
  }

  const handleToggleAlert = async (alertId: string, currentStatus: string) => {
    try {
      const newStatus = currentStatus === 'PAUSED' ? 'ACTIVE' : 'PAUSED'
      
      const response = await fetch(`${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/users/${customer.id}/price-alerts/${alertId}`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ status: newStatus })
      })
      
      if (response.ok) {
        setAlerts(alerts.map(alert => 
          alert.id === alertId ? { ...alert, status: newStatus as any } : alert
        ))
      } else {
        const error = await response.json()
        toast.error(error.message || `We couldn't update that alert right now. Please try again.`)
      }
    } catch (error) {
      console.error('Error updating alert:', error)
      toast.error(`We couldn't update that alert right now. Please try again.`)
    }
  }

  const getAlertTypeIcon = (type: string) => {
    switch (type) {
      case 'PRICE_DROP':
        return (
          <div className="w-8 h-8 bg-red-100 dark:bg-red-900/20 rounded-lg flex items-center justify-center">
            <svg className="w-4 h-4 text-red-600 dark:text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
            </svg>
          </div>
        )
      case 'PRICE_TARGET':
        return (
          <div className="w-8 h-8 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center">
            <svg className="w-4 h-4 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
            </svg>
          </div>
        )
      case 'BACK_IN_STOCK':
        return (
          <div className="w-8 h-8 bg-blue-100 dark:bg-blue-900/20 rounded-lg flex items-center justify-center">
            <svg className="w-4 h-4 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
            </svg>
          </div>
        )
      case 'NEW_LISTING':
        return (
          <div className="w-8 h-8 bg-purple-100 dark:bg-purple-900/20 rounded-lg flex items-center justify-center">
            <svg className="w-4 h-4 text-purple-600 dark:text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
          </div>
        )
      default:
        return (
          <div className="w-8 h-8 bg-gray-100 dark:bg-gray-900/20 rounded-lg flex items-center justify-center">
            <svg className="w-4 h-4 text-gray-600 dark:text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-5 5-5-5h5v-5a7.5 7.5 0 1 0-15 0v5h5" />
            </svg>
          </div>
        )
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'ACTIVE':
        return 'text-green-600 bg-green-100 dark:text-green-400 dark:bg-green-900/20'
      case 'TRIGGERED':
        return 'text-blue-600 bg-blue-100 dark:text-blue-400 dark:bg-blue-900/20'
      case 'PAUSED':
        return 'text-yellow-600 bg-yellow-100 dark:text-yellow-400 dark:bg-yellow-900/20'
      case 'EXPIRED':
        return 'text-gray-600 bg-gray-100 dark:text-gray-400 dark:bg-gray-900/20'
      default:
        return 'text-gray-600 bg-gray-100'
    }
  }

  const getAlertDescription = (alert: PriceAlert) => {
    switch (alert.alert_type) {
      case 'PRICE_DROP':
        return alert.percentage_threshold 
          ? `When price drops ${alert.percentage_threshold}% or more`
          : `When price drops below ${formatAmount((alert.trigger_price || 0) * 100, 'USD')}`
      case 'PRICE_TARGET':
        return `When price reaches ${formatAmount((alert.trigger_price || 0) * 100, 'USD')}`
      case 'BACK_IN_STOCK':
        return `When card is back in stock`
      case 'NEW_LISTING':
        return `When new listings are added`
      default:
        return 'Price alert'
    }
  }

  const sortedAlerts = [...alerts].sort((a, b) => {
    switch (sortBy) {
      case 'card_name':
        return a.card_name.localeCompare(b.card_name)
      case 'trigger_price':
        return (a.trigger_price || 0) - (b.trigger_price || 0)
      case 'created_at':
      default:
        return new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
    }
  })

  if (loading) {
    return (
      <div className={cn("bg-card rounded-lg border border-border p-6", className)}>
        <div className="animate-pulse space-y-4">
          <div className="h-6 bg-gray-200 rounded w-1/3" />
          <div className="space-y-3">
            {[1, 2, 3].map(i => (
              <div key={i} className="flex items-center space-x-4">
                <div className="w-12 h-12 bg-gray-200 rounded-lg" />
                <div className="flex-1 space-y-2">
                  <div className="h-4 bg-gray-200 rounded w-1/2" />
                  <div className="h-3 bg-gray-200 rounded w-1/3" />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className={cn("bg-card rounded-lg border border-red-200 p-6", className)}>
        <div className="flex items-start gap-3">
          <div className="w-6 h-6 bg-red-100 rounded-full flex items-center justify-center mt-0.5">
            <svg className="w-4 h-4 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <div className="flex-1">
            <h3 className="font-medium text-red-900 mb-1">Error Loading Alerts</h3>
            <p className="text-sm text-red-700 mb-4">{error}</p>
            <button
              onClick={loadAlerts}
              className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors text-sm"
            >
              Try Again
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className={cn("bg-card rounded-lg border border-border", className)}>
      {/* Header */}
      <div className="p-6 border-b border-border">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="text-lg font-semibold text-primary mb-2">
              {catalogSku ? 'Price Alerts for This Card' : 'Your Price Alerts'}
            </h3>
            <p className="text-sm text-secondary">
              {alerts.length} alert{alerts.length !== 1 ? 's' : ''} configured
            </p>
          </div>
          <button
            onClick={() => setShowCreateModal(true)}
            className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors text-sm flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Create Alert
          </button>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2">
            <label htmlFor="filter" className="text-sm font-medium text-secondary">Filter:</label>
            <select
              id="filter"
              value={filter}
              onChange={(e) => setFilter(e.target.value as any)}
              className="px-3 py-1 border border-border rounded-md bg-background text-primary text-sm"
            >
              <option value="all">All Alerts</option>
              <option value="active">Active</option>
              <option value="triggered">Triggered</option>
              <option value="paused">Paused</option>
            </select>
          </div>
          
          <div className="flex items-center gap-2">
            <label htmlFor="sort" className="text-sm font-medium text-secondary">Sort by:</label>
            <select
              id="sort"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value as any)}
              className="px-3 py-1 border border-border rounded-md bg-background text-primary text-sm"
            >
              <option value="created_at">Date Created</option>
              <option value="card_name">Card Name</option>
              <option value="trigger_price">Price Target</option>
            </select>
          </div>
        </div>
      </div>

      {/* Alerts List */}
      <div className="p-6">
        {sortedAlerts.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-16 h-16 bg-gray-100 dark:bg-gray-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-5 5-5-5h5v-5a7.5 7.5 0 1 0-15 0v5h5" />
              </svg>
            </div>
            <h4 className="text-lg font-medium text-primary mb-2">No Price Alerts</h4>
            <p className="text-secondary mb-4">
              {catalogSku 
                ? "You haven't set up any price alerts for this card yet."
                : "You haven't created any price alerts yet."
              }
            </p>
            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
            >
              Create Your First Alert
            </button>
          </div>
        ) : (
          <div className="space-y-4">
            {sortedAlerts.map((alert) => (
              <div key={alert.id} className="flex items-start gap-4 p-4 bg-component rounded-lg border border-border">
                {/* Card Image */}
                <div className="flex-shrink-0">
                  {alert.card_image ? (
                    <img 
                      src={alert.card_image} 
                      alt={alert.card_name}
                      className="w-12 h-16 object-cover rounded-md"
                    />
                  ) : (
                    <div className="w-12 h-16 bg-gray-200 rounded-md flex items-center justify-center">
                      <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                      </svg>
                    </div>
                  )}
                </div>

                {/* Alert Type Icon */}
                <div className="flex-shrink-0">
                  {getAlertTypeIcon(alert.alert_type)}
                </div>

                {/* Alert Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between mb-2">
                    <div>
                      <h4 className="font-medium text-primary">{alert.card_name}</h4>
                      {alert.set_name && (
                        <p className="text-sm text-secondary">{alert.set_name}</p>
                      )}
                    </div>
                    <div className="flex items-center gap-2 ml-4">
                      <span className={cn(
                        "px-2 py-1 text-xs font-medium rounded-full capitalize",
                        getStatusColor(alert.status)
                      )}>
                        {alert.status.toLowerCase()}
                      </span>
                    </div>
                  </div>

                  <p className="text-sm text-secondary mb-2">
                    {getAlertDescription(alert)}
                  </p>

                  {/* Current vs Target Price */}
                  {alert.current_price && alert.trigger_price && (
                    <div className="flex items-center gap-4 text-sm mb-2">
                      <span className="text-secondary">
                        Current: <span className="font-medium text-primary">{formatAmount(alert.current_price * 100, 'USD')}</span>
                      </span>
                      <span className="text-secondary">
                        Target: <span className="font-medium text-primary">{formatAmount(alert.trigger_price * 100, 'USD')}</span>
                      </span>
                    </div>
                  )}

                  {/* Notification Methods */}
                  <div className="flex items-center gap-2 mb-3">
                    {alert.email_enabled && (
                      <span className="inline-flex items-center gap-1 px-2 py-1 bg-blue-100 text-blue-700 text-xs rounded-full">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 4.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                        </svg>
                        Email
                      </span>
                    )}
                    {alert.sms_enabled && (
                      <span className="inline-flex items-center gap-1 px-2 py-1 bg-green-100 text-green-700 text-xs rounded-full">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                        </svg>
                        SMS
                      </span>
                    )}
                    {alert.push_enabled && (
                      <span className="inline-flex items-center gap-1 px-2 py-1 bg-purple-100 text-purple-700 text-xs rounded-full">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-5 5-5-5h5v-5a7.5 7.5 0 1 0-15 0v5h5" />
                        </svg>
                        Push
                      </span>
                    )}
                  </div>

                  {/* Alert Stats */}
                  <div className="flex items-center justify-between text-xs text-secondary">
                    <span>
                      Triggered {alert.trigger_count} of {alert.max_triggers} times
                    </span>
                    <span>
                      Created {new Date(alert.created_at).toLocaleDateString()}
                    </span>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex flex-col gap-2">
                  <button
                    onClick={() => handleToggleAlert(alert.id, alert.status)}
                    className={cn(
                      "p-2 rounded-lg transition-colors",
                      alert.status === 'PAUSED'
                        ? "bg-green-100 text-green-600 hover:bg-green-200"
                        : "bg-yellow-100 text-yellow-600 hover:bg-yellow-200"
                    )}
                    title={alert.status === 'PAUSED' ? 'Resume Alert' : 'Pause Alert'}
                  >
                    {alert.status === 'PAUSED' ? (
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h1m4 0h1m-6 4h8m6-4a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    ) : (
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 9v6m4-6v6m7-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    )}
                  </button>
                  
                  <button
                    onClick={() => handleDeleteAlert(alert.id)}
                    className="p-2 bg-red-100 text-red-600 hover:bg-red-200 rounded-lg transition-colors"
                    title="Delete Alert"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Create Alert Modal */}
      <CreatePriceAlertModal
        isOpen={showCreateModal}
        onClose={() => setShowCreateModal(false)}
        onCreated={loadAlerts}
        customer={customer}
        card={card && catalogSku ? { ...card, catalog_sku: catalogSku } : undefined}
        currentPrice={currentPrice}
      />
    </div>
  )
}

import { Card, Checkbox } from "@/components/atoms"
import { convertToLocale } from "@/lib/helpers/money"
import {
  Listbox,
  ListboxButton,
  ListboxOption,
  ListboxOptions,
} from "@headlessui/react"
import { clx } from "@medusajs/ui"
import { ChevronUpDown } from "@medusajs/icons"

import Image from "next/image"
import { cn } from "@/lib/utils"

export const ReturnItemsTab = ({
  order,
  selectedItems,
  handleSelectItem,
  returnReasons,
  error,
}: {
  order: any
  selectedItems: any[]
  handleSelectItem: (item: any, reason_id: string) => void
  returnReasons: any[]
  error: boolean
}) => {
  return (
    <div>
      <Card className="bg-secondary p-4">
        <p className="label-md">
          Seller: <span className="font-semibold">{order.seller.name}</span>
        </p>
      </Card>
      <Card className="flex items-center justify-between p-4">
        <ul className="w-full">
          {order.items.map((item: any) => (
            <li key={item.id} className="md:flex justify-between gap-2 w-full">
              <div className="flex items-center gap-2 md:w-2/3 mb-4 md:mb-0">
                <Checkbox
                  checked={selectedItems.some(
                    (i) => i.line_item_id === item.id
                  )}
                  onChange={() => handleSelectItem(item, "")}
                />
