"use client"

import { usePathname } from "next/navigation"
import { UserNavigation, navigationItems } from "@/components/molecules/UserNavigation/UserNavigation"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"

/** Paths that render standalone (no sidebar/pills) */
const STANDALONE_PATHS = ["/user/verify-email", "/user/register"]

export default function UserLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const pathname = usePathname()

  const isStandalone = STANDALONE_PATHS.some((p) => pathname.endsWith(p))

  if (isStandalone) {
    return <div>{children}</div>
  }

  return (
    <div className="container py-8">
      {/* Mobile pill nav — visible below md */}
      <nav
        className="flex md:hidden overflow-x-auto gap-2 pb-4 mb-4"
        style={{ scrollbarWidth: "none", msOverflowStyle: "none" }}
      >
        <style>{`.user-pill-nav::-webkit-scrollbar { display: none; }`}</style>
        {[...navigationItems, { label: "Settings", href: "/user/settings" }].map(
          (item) => {
            const isActive = pathname.endsWith(item.href)
            return (
              <LocalizedClientLink
                key={item.label}
                href={item.href}
                className="user-pill-nav flex-shrink-0 px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors"
                style={{
                  fontFamily: "var(--font-heading, inherit)",
                  color: isActive
                    ? "var(--brand-primary, #8B5CF6)"
                    : "var(--text-tertiary, #7B72A8)",
                  background: isActive
                    ? "rgba(139, 92, 246, 0.12)"
                    : "var(--bg-surface-1, #18162A)",
                  border: isActive
                    ? "1px solid var(--brand-primary, #8B5CF6)"
                    : "1px solid var(--border-default, #2C2A4A)",
                }}
              >
                {item.label}
              </LocalizedClientLink>
            )
          }
        )}
      </nav>

      {/* Desktop: 240px sidebar + content | Mobile: single column */}
      <div
        className="grid gap-8"
        style={{
          gridTemplateColumns: "240px 1fr",
