      >
        {/* Sidebar — hidden below md */}
        <div className="hidden md:block">
          <UserNavigation />
        </div>

        {/* Main content */}
        <div className="min-w-0 col-span-full md:col-span-1">{children}</div>
      </div>
    </div>
  )
}

