"use client"

import { useState } from 'react'
import Link from 'next/link'

export type VerificationResult = 'success' | 'invalid_token' | 'token_used' | 'token_expired'

interface VerificationStatusProps {
  result: VerificationResult
}

export function VerificationStatus({ result }: VerificationStatusProps) {
  const [resendState, setResendState] = useState<'idle' | 'sending' | 'sent' | 'error'>('idle')

  const handleResend = async () => {
    setResendState('sending')
    try {
      const response = await fetch('/api/auth/email-verification/send', {
        method: 'POST',
        credentials: 'include',
      })
      setResendState(response.ok ? 'sent' : 'error')
    } catch {
      setResendState('error')
    }
  }

  if (result === 'success') {
    return (
      <div className="flex flex-col items-center gap-4 py-12 text-center">
        <div className="flex items-center justify-center w-16 h-16 rounded-full" style={{ background: "rgba(16, 185, 129, 0.15)" }}>
          <svg
            className="w-8 h-8"
            style={{ color: "var(--positive, #10B981)" }}
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
            aria-hidden="true"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h1 className="heading-md" style={{ color: "var(--positive, #10B981)" }}>Email verified!</h1>
        <p className="text-sm max-w-sm" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
          Your email address has been verified. You now have full access to SideDecked.
        </p>
        <Link href="/user" className="text-sm font-medium underline hover:no-underline" style={{ color: "var(--brand-primary, #8B5CF6)" }}>
          Go to your account
        </Link>
      </div>
    )
  }

  const isExpiredOrInvalid = result === 'token_expired' || result === 'invalid_token' || result === 'token_used'

  const errorTitle =
    result === 'token_expired'
      ? 'Verification link expired'
      : result === 'token_used'
        ? 'Link already used'
        : 'Invalid verification link'

  const errorDescription =
    result === 'token_expired'
      ? 'This verification link has expired (links are valid for 24 hours). Request a new one below.'
      : result === 'token_used'
        ? 'This link has already been used. If your email is not yet verified, request a new link below.'
        : 'This verification link is invalid. It may have been copied incorrectly.'

  return (
    <div className="flex flex-col items-center gap-4 py-12 text-center">
      <div className="flex items-center justify-center w-16 h-16 rounded-full" style={{ background: "rgba(239, 68, 68, 0.1)" }}>
        <svg
          className="w-8 h-8"
          style={{ color: "var(--negative, #EF4444)" }}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
          aria-hidden="true"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
        </svg>
      </div>
      <h1 className="heading-md" style={{ color: "var(--negative, #EF4444)" }}>{errorTitle}</h1>
      <p className="text-sm max-w-sm" style={{ color: "var(--text-secondary, #B8B0D8)" }}>{errorDescription}</p>

      {isExpiredOrInvalid && (
        <div className="flex flex-col items-center gap-2">
          {resendState === 'sent' ? (
            <p className="text-sm" style={{ color: "var(--positive, #10B981)" }}>New verification email sent. Check your inbox.</p>
          ) : (
            <button
              type="button"
              onClick={handleResend}
              disabled={resendState === 'sending'}
              className="text-sm font-medium underline hover:no-underline disabled:opacity-50"
              style={{ color: "var(--brand-primary, #8B5CF6)" }}
            >
              {resendState === 'sending' ? 'Sending…' : 'Send new verification email'}
            </button>
          )}
          {resendState === 'error' && (
            <p className="text-xs" style={{ color: "var(--negative, #EF4444)" }}>Failed to send. Please try again.</p>
          )}
        </div>
      )}
    </div>
  )
}

